const raw = ($('MAIN_AI_AGENT').first().json.output ?? '').trim();

// إزالة أي JSON غلط رجع من الـ parser
let text = raw;
try {
  const parsed = JSON.parse(raw);
  if (parsed.text) text = parsed.text;
  if (parsed.messages) {
    return parsed.messages
      .filter(m => m && String(m).trim())
      .slice(0, 3)
      .map((m, index) => ({ 
        json: { 
          ...$json, 
          output: m, 
          messageNumber: index + 1,
          isFirstMessage: index === 0 
        } 
      }));
  }
} catch(e) {}

// تقسيم ذكي بناءً على الجمل
const separators = ['\n\n', '\n', '. ', '! ', '؟ '];
let parts = [text];

for (const sep of separators) {
  if (parts.length >= 2) break;
  const split = text.split(sep).filter(p => p.trim().length > 10);
  if (split.length >= 2 && split.length <= 3) {
    parts = split.map((p, i) => {
      if (sep !== '\n' && sep !== '\n\n' && i < split.length - 1) {
        return p + sep.trim();
      }
      return p;
    });
    break;
  }
}

// ضمان مش أكتر من 3 رسائل
parts = parts.slice(0, 3).filter(p => p.trim());

if (parts.length === 0) parts = [text];

// هنا التعديل الأساسي لإضافة البيانات الجديدة
return parts.map((p, index) => ({
  json: { 
    ...$json, 
    output: p.trim(),
    messageNumber: index + 1, // هيطلع 1، 2، 3
    isFirstMessage: index === 0 // هيطلع true للرسالة الأولى و false للباقي
  }
}));

// 1. استخراج المصفوفة والتأكد من أنها موجودة وليست فارغة
const inputData = $input.all();
if (!inputData || inputData.length === 0 || !inputData[0].json) {
  return { json: { chat_history: [] } };
}

const messages = inputData.map(item => item.json);

// 2. ترتيب الرسائل زمنيًا من الأقدم إلى الأحدث
const sortedMessages = messages.sort((a, b) => {
  const dateA = a.created_at ? new Date(a.created_at) : new Date();
  const dateB = b.created_at ? new Date(b.created_at) : new Date();
  return dateA - dateB;
});

// 3. أخذ آخر 10 رسائل فقط
const limitedMessages = sortedMessages.slice(-10);

// 4. تحويل الرسائل لتنسيق مفهوم للذكاء الاصطناعي
const chatHistory = limitedMessages.map(msg => {
  const isClient = msg.direction === 'inbound';
  return {
    role: isClient ? 'user' : 'assistant',
    content: msg.content || ''
  };
});

// 5. إرجاع النتيجة
return {
  json: {
    chat_history: chatHistory
  }
};

const wh = $('WEBHOOK_TRIGGER1').first().json;
const body = wh.body || wh;
const data = body.data || {};
const key = data.key || {};
const phone = String(key.remoteJid || '').split('@')[0].replace(/[^0-9]/g, '');
const fromMe = key.fromMe === true;
const m = data.message || {};
const text = m.conversation
  || (m.extendedTextMessage && m.extendedTextMessage.text)
  || (m.imageMessage && m.imageMessage.caption)
  || (m.videoMessage && m.videoMessage.caption) || '';
const hasAudio = !!m.audioMessage;
const skip = fromMe || (!text && !hasAudio) || !phone;
return { json: {
  phone, name: data.pushName || '', wa_message_id: key.id || null,
  customer_message: text, has_audio: hasAudio, from_me: fromMe, skip
} };
